import{c as n}from"./app.8935f5f1.js";const s={},a=n('<p>在nodejs中，提供了exports 和 require 两个对象，其中 exports 是模块公开的接口，require 用于从外部获取一个模块的接口，即所获取模块的 exports 对象。在我们自己写模块的时候，需要在模块最后写好模块接口，声明这个模块对外暴露什么内容，module.exports 提供了暴露接口的方法。</p><ol><li>返回一个JSON Object</li></ol><div class="language-jsx ext-jsx"><pre class="language-jsx"><code><span class="token comment">//app.js</span>\n<span class="token keyword">var</span> app <span class="token operator">=</span> <span class="token punctuation">{</span>\n    name<span class="token operator">:</span> <span class="token string">&#39;app&#39;</span><span class="token punctuation">,</span>\n    version<span class="token operator">:</span> <span class="token string">&#39;1.0.0&#39;</span><span class="token punctuation">,</span>\n    sayHello<span class="token operator">:</span><span class="token function">sayHello</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span>\n    <span class="token function-variable function">sayName</span><span class="token operator">:</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">name</span><span class="token punctuation">)</span><span class="token punctuation">{</span>\n        console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">.</span>name<span class="token punctuation">)</span><span class="token punctuation">;</span>\n    <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n<span class="token keyword">function</span> <span class="token function">sayHello</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span>\n    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;Hello&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\nmodule<span class="token punctuation">.</span>exports <span class="token operator">=</span> app<span class="token punctuation">;</span>\n</code></pre></div><p>调用方法：(可传入参数)</p><div class="language-jsx ext-jsx"><pre class="language-jsx"><code><span class="token keyword">var</span> app <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;./app.js&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\napp<span class="token punctuation">.</span><span class="token function">sayName</span><span class="token punctuation">(</span><span class="token string">&#39;hello&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token comment">//hello</span>\napp<span class="token punctuation">.</span><span class="token function">sayHello</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token comment">//hello</span>\n</code></pre></div><ol start="2"><li>返回一个模块函数</li></ol><div class="language-jsx ext-jsx"><pre class="language-jsx"><code><span class="token comment">//function.js</span>\n<span class="token keyword">var</span> <span class="token function-variable function">func1</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n   console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;func1&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span><span class="token punctuation">;</span>\n \n<span class="token keyword">var</span> <span class="token function-variable function">func2</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n   console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;func2&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span><span class="token punctuation">;</span>\n \nexports<span class="token punctuation">.</span>function1 <span class="token operator">=</span> func1<span class="token punctuation">;</span>\nexports<span class="token punctuation">.</span>function2 <span class="token operator">=</span> func2<span class="token punctuation">;</span>\n</code></pre></div><p>调用方法：</p><div class="language-jsx ext-jsx"><pre class="language-jsx"><code><span class="token keyword">var</span> functions <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&quot;./function.js&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\nfunctions<span class="token punctuation">.</span><span class="token function">function1</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\nfunctions<span class="token punctuation">.</span><span class="token function">function2</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre></div><ol start="3"><li>返回一个构造函数</li></ol><div class="language-jsx ext-jsx"><pre class="language-jsx"><code><span class="token comment">//CLASS.js</span>\n<span class="token keyword">var</span> <span class="token function-variable function">CLASS</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">args</span><span class="token punctuation">)</span><span class="token punctuation">{</span>\n     <span class="token keyword">this</span><span class="token punctuation">.</span>args <span class="token operator">=</span> args<span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\nmodule<span class="token punctuation">.</span>exports <span class="token operator">=</span> <span class="token constant">CLASS</span><span class="token punctuation">;</span>\n</code></pre></div><p>调用方法：</p><div class="language-jsx ext-jsx"><pre class="language-jsx"><code><span class="token keyword">var</span> <span class="token constant">CLASS</span> <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;./CLASS.js&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token keyword">var</span> c <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">CLASS</span><span class="token punctuation">(</span><span class="token string">&#39;arguments&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre></div><ol start="4"><li>返回一个实例对象：</li></ol><div class="language-jsx ext-jsx"><pre class="language-jsx"><code><span class="token comment">//CLASS.js</span>\n<span class="token keyword">var</span> <span class="token function-variable function">CLASS</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span>\n    <span class="token keyword">this</span><span class="token punctuation">.</span>name <span class="token operator">=</span> <span class="token string">&quot;class&quot;</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n<span class="token constant">CLASS</span> <span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function-variable function">func</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span>\n    <span class="token function">alert</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">.</span>name<span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\nmodule<span class="token punctuation">.</span>exports <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">CLASS</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre></div><p>调用方法：</p><div class="language-swift ext-swift"><pre class="language-swift"><code><span class="token keyword">var</span> c <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span>&#39;<span class="token operator">./</span><span class="token constant">CLASS</span><span class="token punctuation">.</span>js&#39;<span class="token punctuation">)</span><span class="token punctuation">;</span>\nc<span class="token punctuation">.</span><span class="token keyword">func</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token comment">//&quot;class&quot;</span>\n</code></pre></div>',17);s.render=function(n,s){return a};export{s as default};
